-- ===== 블로그 샘플 데이터 =====
INSERT OR IGNORE INTO blog_posts (slug, title, category, summary, content, tags, author) VALUES
('implant-guide-2025', '임플란트, 꼭 알아야 할 5가지', '임플란트', '임플란트 수술 전 환자분들이 가장 많이 궁금해하시는 5가지 질문에 대해 구강외과 전문의가 직접 답변드립니다.', '<h2>1. 임플란트란 무엇인가요?</h2><p>임플란트는 상실된 치아 부위의 잇몸뼈(치조골)에 인공 치근(티타늄 나사)을 심고, 그 위에 인공 치아(보철)를 연결하는 치료입니다.</p><h2>2. 아프지 않나요?</h2><p>수술 중에는 마취로 인해 거의 통증이 없습니다. 수술 후 2~3일간 가벼운 부기와 불편감이 있을 수 있지만, 처방 진통제로 충분히 관리됩니다. 구강외과 전문의가 수술하면 절개 범위가 최소화되어 회복이 빠릅니다.</p><h2>3. 뼈가 부족해도 가능한가요?</h2><p>가능합니다. 뼈이식이나 상악동 거상술 같은 추가 시술을 통해 부족한 뼈를 보충한 후 임플란트를 식립합니다. 이것이 바로 구강외과 전문의의 전문 영역입니다.</p><h2>4. 수명은 얼마나 되나요?</h2><p>관리에 따라 다르지만, 적절한 구강 관리와 정기 검진을 받으시면 10년 이상 사용하실 수 있습니다. 실제로 20년 이상 사용하시는 분들도 많습니다.</p><h2>5. 비용은 얼마인가요?</h2><p>환자분의 뼈 상태, 뼈이식 여부, 보철 종류에 따라 달라집니다. 정확한 비용은 CT 촬영 후 무료 상담 시 안내드립니다.</p>', '임플란트,비용,수술,FAQ', '이태형 대표원장'),

('cerec-same-day', 'CEREC 당일 보철이란? — 하루만에 끝나는 치과 치료', 'CEREC', '본 뜨고, 기공소 보내고, 기다리고, 다시 오는 과정 없이 하루 만에 보철을 완성하는 CEREC 시스템을 소개합니다.', '<h2>CEREC이란?</h2><p>CEREC은 Chairside Economical Restoration of Esthetic Ceramics의 약자로, 진료실 안에서 세라믹 보철을 디지털로 설계하고 제작하는 시스템입니다.</p><h2>기존 보철 과정과 차이점</h2><p>기존 방식은 본을 뜨고(인상채득) → 기공소에 보내고 → 7~14일 대기 → 다시 내원해서 장착하는 과정을 거칩니다. CEREC은 이 모든 과정을 <strong>약 2시간</strong>으로 단축합니다.</p><h2>과정</h2><p><strong>1단계</strong>: PrimeScan 구강 스캐너로 3D 디지털 촬영 (5분)<br><strong>2단계</strong>: AI가 보철 설계 (10분)<br><strong>3단계</strong>: CEREC MC X 밀링 머신이 세라믹 블록을 깎아 보철 제작 (15분)<br><strong>4단계</strong>: SpeedFire로 소성 후 장착 (30분)</p><h2>이런 분께 추천합니다</h2><p>여러 번 치과에 오기 힘든 바쁜 직장인, 멀리서 내원하시는 분, 한 번 방문으로 치료를 끝내고 싶은 분께 특히 추천드립니다.</p>', 'CEREC,당일보철,디지털치과,세라믹', '이태형 대표원장'),

('wisdom-tooth-specialist', '사랑니 발치, 왜 구강외과 전문의에게 받아야 할까?', '구강외과', '매복 사랑니 발치는 잇몸을 절개하고 뼈를 삭제해야 하는 수술입니다. 수술 경험이 풍부한 구강외과 전문의가 더 안전하고 빠르게 발치합니다.', '<h2>사랑니 발치도 수술입니다</h2><p>누워있는 매복 사랑니는 잇몸을 절개하고, 뼈를 일부 제거한 후, 치아를 분리해서 발치합니다. 이것은 엄연한 수술이며, 신경 손상 위험도 있습니다.</p><h2>구강외과 전문의가 하면 뭐가 다른가요?</h2><p>구강악안면외과 전문의는 대학병원에서 4년간 전문 수술 수련을 받은 전문의입니다. 뼈를 보는 눈, 신경을 피하는 기술, 봉합의 정밀함이 일반 치과의사와 다릅니다.</p><h2>강남치과의원의 차이점</h2><p>3D CT로 신경 위치를 정확히 파악하고, 최소 절개로 빠른 회복을 추구합니다. 구강외과 전문의 2인이 상주하므로, 응급 상황에도 즉시 대응 가능합니다.</p>', '사랑니,발치,구강외과,매복사랑니', '최민혜 원장');

-- ===== 비포/애프터 샘플 데이터 =====
INSERT OR IGNORE INTO before_after_cases (slug, title, category, patient_info, treatment_desc, before_image, after_image, duration, doctor, tags) VALUES
('implant-case-01', '상악 전치부 임플란트 + CEREC 당일 보철', '임플란트', '60대 남성', '상악 앞니 2개가 파절되어 발치 후 임플란트를 식립하고, CEREC으로 당일 임시 보철을 제작했습니다. 3D CT 정밀 진단 후 디지털 가이드를 이용한 정확한 식립으로 최소 절개, 빠른 회복을 달성했습니다.', '/static/cases/placeholder-before.svg', '/static/cases/placeholder-after.svg', '당일 수술 + 3개월 후 최종보철', '이태형 대표원장', '임플란트,CEREC,상악,전치부'),

('cerec-crown-case-01', 'CEREC 당일 크라운 — 2시간 만에 완성', 'CEREC', '40대 여성 직장인', '큰 충치로 인해 크라운이 필요했으나, 직장인이라 여러 번 내원하기 어려운 상황. PrimeScan으로 디지털 스캔 후 CEREC MC X로 세라믹 크라운을 당일 제작·장착했습니다.', '/static/cases/placeholder-before.svg', '/static/cases/placeholder-after.svg', '약 2시간 (1회 내원)', '이태형 대표원장', 'CEREC,크라운,당일보철,직장인'),

('invisalign-case-01', '인비절라인 투명교정 — 덧니 개선', '교정', '30대 여성', '앞니 덧니로 인한 심미적 불만과 구강 위생 관리 어려움. 인비절라인 투명교정으로 약 10개월간 치료하여 가지런한 치아를 완성했습니다.', '/static/cases/placeholder-before.svg', '/static/cases/placeholder-after.svg', '약 10개월', '최민혜 원장', '인비절라인,투명교정,덧니,심미');
